mapper.select:
SELECT tone_id, member_id, style, characteristics, sample_text, created_at, updated_at
FROM sm_blog_tone
WHERE member_id = #{memberId}

mapper.update:
UPDATE sm_blog_tone
SET style = #{style},
    characteristics = #{characteristics, typeHandler=com.crown.common.typehandler.JsonListStringTypeHandler},
    sample_text = #{sampleText}
WHERE member_id = #{memberId}

mapper.select:
SELECT post_id, member_id, subject, content, media_urls, additional_info, platform, status, error_message, published_url, scheduled_at, published_at, created_at, updated_at FROM sm_blog_post WHERE member_id = #{memberId}
AND status = #{status}
ORDER BY created_at DESC

mapper.update:
UPDATE sm_blog_post
SET content = #{content}, status = #{status}, updated_at = NOW()
WHERE post_id = #{postId}

UPDATE sm_blog_post
SET subject = #{subject}, updated_at = NOW()
WHERE post_id = #{postId}
